// Collect the distinct lookup keys the parallel searches need:
//  - orgNames : distinct Buyer + Seller organization names (dept_name)
//  - itemCodes: distinct Buyer + Seller item codes (material_code)
//  - uomNames : distinct Buyer + Seller UOM names (OPTIONAL columns; blank -> item base UOM)
// The parsed excel arrives as import_data: numeric-keyed rows plus name/size/type meta keys.
const excelData = JSON.parse({{workflowparams:import_data}});

const orgNames = [];
const itemCodes = [];
const uomNames = [];

const push = (arr, v) => {
  const s = v === undefined || v === null ? "" : String(v).trim();
  if (s && arr.indexOf(s) === -1) arr.push(s);
};

Object.keys(excelData).forEach((k) => {
  if (/^\d+$/.test(k)) {
    const row = excelData[k] || {};
    push(orgNames, row["Buyer Organization"]);
    push(orgNames, row["Seller Organization"]);
    push(itemCodes, row["Buyer Item Code"]);
    push(itemCodes, row["Seller Item Code"]);
    push(uomNames, row["Buyer Item UOM"]);
    push(uomNames, row["Seller Item UOM"]);
  }
});

// Never feed an empty array into an `equalAny` filter; a "0" sentinel matches nothing.
if (orgNames.length === 0) orgNames.push("0");
if (itemCodes.length === 0) itemCodes.push("0");
if (uomNames.length === 0) uomNames.push("0");

return { orgNames: orgNames, itemCodes: itemCodes, uomNames: uomNames };

// Resolve org names -> ids and item codes -> ids (scoped to the resolved org),
// derive buyer/seller UOM from each item's based_uom, and validate every row.
// Any hard problem accumulates into `errors` (-> code 400, insert nothing).
// On success, de-duplicate rows WITHIN the file and hand the unique candidates on.
const excelData = JSON.parse({{workflowparams:import_data}});
const orgList = {{node:search_org.data.data}} || [];
const itemList = {{node:search_item.data.data}} || [];
const uomList = {{node:search_uom.data.data}} || [];

const str = (v) => (v === undefined || v === null ? "" : String(v).trim());

// org name -> [ids]  (detect not-found / ambiguous)
const orgByName = {};
orgList.forEach((o) => {
  const name = str(o.dept_name);
  if (!name) return;
  if (!orgByName[name]) orgByName[name] = [];
  if (orgByName[name].indexOf(String(o.id)) === -1) orgByName[name].push(String(o.id));
});

// (material_code|organization_id) -> [{id, item}]  (detect ambiguous item within an org)
const itemByCodeOrg = {};
itemList.forEach((it) => {
  const code = str(it.material_code);
  const org = String(it.organization_id);
  if (!code || !org) return;
  const key = code + "|" + org;
  if (!itemByCodeOrg[key]) itemByCodeOrg[key] = [];
  itemByCodeOrg[key].push({ id: String(it.id), item: it });
});

const resolveOrg = (name, errors, label, role) => {
  if (!name) { errors.push(label + ": " + role + " Organization is required."); return ""; }
  const ids = orgByName[name];
  if (!ids || ids.length === 0) { errors.push(label + ': ' + role + ' Organization "' + name + '" not found.'); return ""; }
  if (ids.length > 1) { errors.push(label + ': ' + role + ' Organization "' + name + '" is ambiguous.'); return ""; }
  return ids[0];
};

const resolveItem = (code, orgId, errors, label, role) => {
  if (!orgId) return { id: "", item: null }; // org already errored; skip a second complaint
  if (!code) { errors.push(label + ": " + role + " Item Code is required."); return { id: "", item: null }; }
  const matches = itemByCodeOrg[code + "|" + orgId];
  if (!matches || matches.length === 0) { errors.push(label + ': ' + role + ' Item Code "' + code + '" not found in the ' + role + ' Organization.'); return { id: "", item: null }; }
  if (matches.length > 1) { errors.push(label + ': ' + role + ' Item Code "' + code + '" is ambiguous in the ' + role + ' Organization.'); return { id: "", item: null }; }
  return { id: matches[0].id, item: matches[0].item };
};

// Resolve the buyer/seller UOM. Blank column -> the item's base UOM. When a UOM
// name IS supplied we still validate it: the name must resolve to a UOM id that is
// valid for THIS item (its based_uom or one of its table_uom_conversion rows).
// UOM names are not globally unique, so match by name AND require a valid-for-item id.
const resolveUom = (match, uomNameRaw, errors, label, role) => {
  if (!match || !match.id) return ""; // item already errored
  const item = match.item || {};
  const based = str(item.based_uom);
  const conv = Array.isArray(item.table_uom_conversion) ? item.table_uom_conversion : [];
  const validIds = {};
  conv.forEach((c) => { const a = str(c.alt_uom_id); if (a) validIds[a] = true; });
  if (based) validIds[based] = true;

  const name = str(uomNameRaw);
  if (!name) {
    if (!based) { errors.push(label + ": " + role + " Item has no base UOM; please provide a " + role + " Item UOM."); return ""; }
    return based;
  }
  const named = uomList.filter((u) => str(u.uom_name) === name);
  if (named.length === 0) { errors.push(label + ': ' + role + ' Item UOM "' + name + '" not found.'); return ""; }
  let matched = "";
  for (let n = 0; n < named.length; n++) {
    const id = String(named[n].id);
    if (validIds[id]) { matched = id; break; }
  }
  if (!matched) { errors.push(label + ': ' + role + ' Item UOM "' + name + '" is not a valid UOM for this item.'); return ""; }
  return matched;
};

const rows = [];
Object.keys(excelData).forEach((k) => {
  if (/^\d+$/.test(k)) rows.push({ idx: parseInt(k, 10), data: excelData[k] || {} });
});
rows.sort((a, b) => a.idx - b.idx);

const errors = [];
const candidates = [];

rows.forEach((r, i) => {
  const row = r.data;
  const label = "Row " + (i + 1);
  const buyerOrgName = str(row["Buyer Organization"]);
  const sellerOrgName = str(row["Seller Organization"]);
  const buyerCode = str(row["Buyer Item Code"]);
  const sellerCode = str(row["Seller Item Code"]);

  const buyerOrgId = resolveOrg(buyerOrgName, errors, label, "Buyer");
  const sellerOrgId = resolveOrg(sellerOrgName, errors, label, "Seller");

  if (buyerOrgId && sellerOrgId && buyerOrgId === sellerOrgId) {
    errors.push(label + ": Buyer Organization and Seller Organization cannot be the same.");
  }

  const buyer = resolveItem(buyerCode, buyerOrgId, errors, label, "Buyer");
  const seller = resolveItem(sellerCode, sellerOrgId, errors, label, "Seller");
  const buyerUom = resolveUom(buyer, row["Buyer Item UOM"], errors, label, "Buyer");
  const sellerUom = resolveUom(seller, row["Seller Item UOM"], errors, label, "Seller");

  const rate = parseFloat(row["Conversion Rate"]);
  if (isNaN(rate) || rate <= 0) {
    errors.push(label + ": Conversion Rate must be a number greater than 0.");
  }

  if (buyerOrgId && sellerOrgId && buyerOrgId !== sellerOrgId &&
      buyer.id && buyerUom && seller.id && sellerUom &&
      !isNaN(rate) && rate > 0) {
    candidates.push({
      buyer_org_id: buyerOrgId,
      buyer_item_id: buyer.id,
      buyer_uom_id: buyerUom,
      seller_org_id: sellerOrgId,
      seller_item_id: seller.id,
      seller_uom_id: sellerUom,
      conversion_rate: Math.round(rate * 1000) / 1000,
      is_active: 1,
      _label: 'Buyer "' + buyerCode + '" → Seller "' + sellerCode + '"',
    });
  }
});

if (errors.length > 0) {
  return { code: "400", message: errors.join("\n"), entries: "[]", buyerItemIds: ["0"], dupInFile: "[]" };
}

// de-duplicate WITHIN the file on the per-seller uniqueness key; keep the first.
const seen = {};
const unique = [];
const dupInFile = [];
candidates.forEach((c) => {
  const key = c.buyer_org_id + "|" + c.seller_org_id + "|" + c.buyer_item_id + "|" + c.buyer_uom_id;
  if (seen[key]) { dupInFile.push(c._label); return; }
  seen[key] = true;
  unique.push(c);
});

const buyerItemIds = [];
unique.forEach((c) => { if (buyerItemIds.indexOf(c.buyer_item_id) === -1) buyerItemIds.push(c.buyer_item_id); });
if (buyerItemIds.length === 0) buyerItemIds.push("0");

return {
  code: "200",
  message: "",
  entries: JSON.stringify(unique),
  buyerItemIds: buyerItemIds,
  dupInFile: JSON.stringify(dupInFile),
};

// Compare the unique candidates against EXISTING active aliases (fetched by
// buyer_item_id) and split into insertable rows vs duplicates. On the first pass
// any duplicate (in-DB or in-file) returns 409 to ask the user to confirm skipping;
// once confirmed (skipDuplicates="true") the non-duplicate rows are handed to the
// insert loop. A 400 from the resolve step is passed straight through (0 inserts).
const codeIn = {{node:code_resolve.data.code}};
const message = {{node:code_resolve.data.message}};
const entriesStr = {{node:code_resolve.data.entries}};
const dupInFileStr = {{node:code_resolve.data.dupInFile}};
const existing = {{node:search_existing.data.data}} || [];
const skipDuplicates = String({{workflowparams:skipDuplicates}} || "");

if (String(codeIn) === "400") {
  return { code: "400", message: message, toInsert: [], inserted: "0", warning: "", duplicates: "" };
}

let candidates = [];
try { candidates = JSON.parse(entriesStr || "[]"); } catch (e) { candidates = []; }
let dupInFile = [];
try { dupInFile = JSON.parse(dupInFileStr || "[]"); } catch (e) { dupInFile = []; }

const existingKeys = {};
existing.forEach((r) => {
  const key = String(r.buyer_org_id) + "|" + String(r.seller_org_id) + "|" + String(r.buyer_item_id) + "|" + String(r.buyer_uom_id);
  existingKeys[key] = true;
});

const toInsert = [];
const dbDup = [];
candidates.forEach((c) => {
  const key = c.buyer_org_id + "|" + c.seller_org_id + "|" + c.buyer_item_id + "|" + c.buyer_uom_id;
  if (existingKeys[key]) { dbDup.push(c._label || key); return; }
  toInsert.push(c);
});

const allDup = dbDup.concat(dupInFile);

if (allDup.length > 0 && skipDuplicates !== "true") {
  const parts = [];
  if (dbDup.length > 0) parts.push(dbDup.length + " already exist as active alias(es): " + dbDup.join("; "));
  if (dupInFile.length > 0) parts.push(dupInFile.length + " duplicated within the file: " + dupInFile.join("; "));
  return {
    code: "409",
    message: parts.join("\n") + "\n\nContinue and skip them?",
    toInsert: [],
    inserted: "0",
    warning: "",
    duplicates: allDup.join("; "),
  };
}

const warnings = [];
if (dbDup.length > 0) warnings.push("Skipped " + dbDup.length + " row(s) that already exist: " + dbDup.join("; ") + ".");
if (dupInFile.length > 0) warnings.push("Skipped " + dupInFile.length + " duplicate row(s) within the file.");
if (toInsert.length === 0) warnings.push("No new aliases to import.");

return {
  code: "200",
  message: "",
  toInsert: toInsert,
  inserted: String(toInsert.length),
  warning: warnings.join("\n"),
  duplicates: "",
};
